import{_ as r,O as a,H as o,f as n,k as i,i as l}from"./chunks/framework.Pt2pSV98.js";const P=JSON.parse('{"title":"Prompt","description":"用户给 AI 的输入指令，是决定输出质量的最关键因素","frontmatter":{"title":"Prompt","description":"用户给 AI 的输入指令，是决定输出质量的最关键因素","difficulty":"beginner"},"headers":[],"relativePath":"terms/prompt.md","filePath":"terms/prompt.md"}'),p={name:"terms/prompt.md"};function m(s,t,h,d,u,c){const e=a("DifficultyBadge");return o(),n("div",null,[i(e,{level:"beginner"}),t[0]||(t[0]=l('<h1 id="prompt" tabindex="-1">Prompt <a class="header-anchor" href="#prompt" aria-label="Permalink to &quot;Prompt&quot;">​</a></h1><p>Prompt 是你与 AI 对话的**&quot;遥控器&quot;**。你给它什么指令，它就往什么方向走。同一个模型，好的 Prompt 和差的 Prompt 产出的结果天差地别。</p><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>Prompt（提示词）是用户输入给 LLM 的文字指令，模型根据它来生成回应。Prompt 的质量直接决定输出的质量。包括角色设定、任务描述、输出格式等要素。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>想象你面前有一个<strong>极度聪明但缺乏常识的新同事</strong>：</p><ul><li>你说&quot;写个报告&quot;→ 他会不知所措，产出质量随机</li><li>你说&quot;你是一个数据分析师，请根据以下销售数据，用 3 个段落总结关键趋势，每段不超过 100 字&quot;→ 他立刻明白该做什么、以什么身份做、产出什么格式</li></ul><p>好的 Prompt 就像<strong>给新同事一份清晰的工作说明书</strong>——告诉他角色、任务、约束和期望产出。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>Prompt 通常分为两层：</p><p><strong>System Prompt（系统提示词）</strong> ：设定模型的角色、行为边界和输出风格，在整个对话中持续生效。例如：&quot;你是一个专业的中文翻译助手，只做中英互译，不回答其他问题。&quot;</p><p><strong>User Prompt（用户提示词）</strong> ：每次对话中你输入的具体问题或任务。模型将 System Prompt + 历史对话 + 当前 User Prompt 一起送入上下文窗口，然后逐 Token 预测输出。</p><p>进阶的 Prompt 技巧包括思维链（Chain of Thought）、少样本提示（Few-shot）和结构化输出要求等。</p><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/context-window.html">上下文窗口</a> —— Prompt 消耗上下文容量</li><li><a href="/ai-knowledge/terms/token.html">Token</a> —— Prompt 被切分成 Token 后送入模型</li><li><a href="/ai-knowledge/terms/fine-tuning.html">微调 (Fine-tuning)</a> —— 另一种定制模型行为的方式</li></ul><h2 id="快速记忆" tabindex="-1">快速记忆 <a class="header-anchor" href="#快速记忆" aria-label="Permalink to &quot;快速记忆&quot;">​</a></h2><p>Garbage in, garbage out——你给模型什么水平的输入，它就回你什么水平的输出。写好 Prompt 是性价比最高的 AI 技能。</p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/docs/guides/prompt-engineering" target="_blank" rel="noreferrer">OpenAI Prompt Engineering Guide</a></li><li><a href="https://docs.anthropic.com/en/docs/build-with-claude/prompt-engineering" target="_blank" rel="noreferrer">Anthropic Prompt 设计指南</a></li></ul>',19))])}const g=r(p,[["render",m]]);export{P as __pageData,g as default};
